SELECT /*+ INDEX_DESC(A PPS_USIM_INFO_IDX1) */ TELCO_CD, USIM_MODEL, SN, USIM_SN, STATUS, F_GET_KT_CODE_NM('PPS_USIM_INFO', 'STATUS', STATUS) STATUS_NM, CR_SEQ, CR_PRICE, TO_CHAR(CR_DATE, 'YYYY-MM-DD') CR_DATE, FN_GET_USRNM(CR_ADMIN) AS CR_ADMIN_NM, CR_ADMIN, OUT_FLAG, OUT_SEQ, TO_CHAR(OUT_DATE, 'YYYY-MM-DD') OUT_DATE, F_GET_AGENT_NM(OUT_AGENT) OUT_AGENT_NM, OUT_AGENT, FN_GET_USRNM(OUT_ADMIN) AS OUT_ADMIN_NM, OUT_ADMIN, OPEN_FLAG, TO_CHAR(OPEN_DATE, 'YYYY-MM-DD') OPEN_DATE, CONTRACT_NUM, BACK_FLAG, BACK_SEQ, TO_CHAR(BACK_DATE, 'YYYY-MM-DD') BACK_DATE, FN_GET_USRNM(BACK_ADMIN) AS BACK_ADMIN_NM, BACK_ADMIN, REMARK FROM PPS_USIM_INFO A WHERE CR_DATE > TO_DATE('20150101', 'YYYYMMDD')
AND REMARK LIKE '%' || #{searchNm} || '%'
AND CR_SEQ = #{searchNm}
AND OUT_SEQ = #{searchNm}
AND BACK_SEQ = #{searchNm}
AND CONTRACT_NUM = #{searchNm}
AND CR_DATE >= TO_DATE(#{startDtCreate}, 'YYYY-MM-DD')
AND CR_DATE < TO_DATE(#{endDtCreate}, 'YYYY-MM-DD')+1
AND OUT_DATE >= TO_DATE(#{startDtOut}, 'YYYY-MM-DD')
AND OUT_DATE < TO_DATE(#{endDtOut}, 'YYYY-MM-DD')+1
AND BACK_DATE >= TO_DATE(#{startDtBack}, 'YYYY-MM-DD')
AND BACK_DATE < TO_DATE(#{endDtBack}, 'YYYY-MM-DD')+1
AND STATUS = #{searchStatus}
AND OUT_AGENT = #{searchAgentNm}
AND USIM_MODEL= #{searchUsimSnHeader}
AND SN >= LPAD(#{searchUsimSnStart}, 7, '0')
AND SN <= LPAD(#{searchUsimSnEnd}, 7, '0')

