SELECT /*+ INDEX_DESC(A PPS_USIM_BACK_IDX1) */ BACK_SEQ, USIM_MODEL, START_SN, END_SN, BACK_ADMIN, FN_GET_USRNM(BACK_ADMIN) AS BACK_ADMIN_NM, TO_CHAR(BACK_DATE, 'YYYY-MM-DD HH24:MI:SS') BACK_DATE, BACK_AGENT, F_GET_AGENT_NM(BACK_AGENT) BACK_AGENT_NM, USIM_CNT, CANCEL_FLAG, TO_CHAR(CANCEL_DATE, 'YYYY-MM-DD') CANCEL_DATE, CANCEL_ADMIN, FN_GET_USRNM(CANCEL_ADMIN) AS CANCEL_ADMIN_NM, REMARK FROM PPS_USIM_BACK A WHERE BACK_DATE > TO_DATE('2015-01-01','YYYY-MM-DD')
AND REMARK LIKE '%' || #{searchNm} || '%'
AND BACK_SEQ = #{searchNm}
AND BACK_AGENT = #{searchAgentNm}
AND BACK_DATE >= TO_DATE(#{startDt}, 'YYYY-MM-DD')
AND BACK_DATE < TO_DATE(#{endDt}, 'YYYY-MM-DD')+1
AND USIM_MODEL = #{searchUsimSnHeader}
AND END_SN >= LPAD(#{searchUsimSnStart}, 7, '0')
AND( (START_SN BETWEEN LPAD(#{searchUsimSnStart}, 7, '0') AND LPAD(#{searchUsimSnEnd}, 7, '0')) OR (END_SN BETWEEN LPAD(#{searchUsimSnStart}, 7, '0') AND LPAD(#{searchUsimSnEnd}, 7, '0')) OR ( START_SN <= LPAD(#{searchUsimSnEnd}, 7, '0') AND END_SN >= LPAD(#{searchUsimSnStart}, 7, '0')))
AND START_SN <= LPAD(#{searchUsimSnEnd}, 7, '0')

